import { useState, useEffect } from 'react'

export default function App() {
  const [sec, setSec] = useState(0)
  useEffect(() => {
    const id = setInterval(() => setSec((s) => s + 1), 1000)
    return () => clearInterval(id)
  }, [])
  return <h1>已运行 {sec} 秒</h1>
}
